295     return false;
296 
297   bool Overflow = false;
298   if (Opcode == Instruction::Add)
299     (void)BVal->sadd_ov(*CVal, Overflow);
300   else
301     (void)BVal->ssub_ov(*CVal, Overflow);
302 
303   return !Overflow;
304 }
